-- shows need live and epinum defaualt 0
CREATE TABLE shows(
	id int AUTO_INCREMENT PRIMARY KEY NOT NULL,
	show_name varchar(50) NOT NULL,
    show_type varchar(50) NOT NUll,
    about varchar(1500) NOT NULL,
    img varchar(300) NOT NULL,
    img_b varchar(300) NOT NULL,
    category varchar(50) NOT NULL,
    sub_category varchar(50) NOT NULL,
    video_type varchar(20) NULL,
    v_link varchar(400) NULL,
    host_id varchar(100) NOT NULL,
    host_name varchar(50) NULL,
    host_img varchar(300) NULL,
    credits varchar(1000) NULL,
    show_date date NULL,
    start_time time(0) NULL,
    end_time time(0) NULL,
    price INT(0) NULL,
    payment varchar(1000) NUll,
    patreon varchar(1000) NUll,
    wp_title varchar(80) NUll,
    webpage varchar(1000) NUll,
    eighteen_plus boolean,
	booked boolean,
    paid boolean,
    canceled boolean,
    verified boolean,
    time_stamp TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	INDEX idx_events_showId (id)
);

INSERT INTO shows(show_name, show_type, about, img, img_b, category, sub_category, video_type, v_link, host_id, host_name, host_img, credits, show_date, start_time, end_time, price, payment, patreon, wp_title, webpage, eighteen_plus, booked, paid, canceled, verified) VALUES('Vespertine 2015-2019 show reel',"one_off","Featured productions include: HiNGE, Midsummer, Rocky Horror Circus Show, and No Graves No Masters. \n Thumbnail photo taken at our 2019 Halloween ball, Haunt, by Trevor Tarin.","https://i.vimeocdn.com/video/836269509_640x360.webp?r=pad","http://www.vespertinecircus.com/wp-content/uploads/2020/05/wp2174026-metal-texture-wallpapers.jpg","performance", "story","vimeo", "https://player.vimeo.com/video/376992272", '1', 'The Vespertine Circus',"http://www.vespertinecircus.com/wp-content/uploads/2011/12/hingetroupe1crop-1024x1024.jpg", 'Nina Sawant, Christine Lee, Lyra Levin, Seanmichael Polaris, Janelle Dinosaurs, Colin Creveling, and Bunny Holmes.', '2020-08-23', '11:27:00', '12:27:00', '0',"paymentlink","patreonLink","Learn more about us here:", "http://www.vespertinecircus.com/", false, true, false, false, true);


